class MyCalendarThree {
public:
    map<int, int> events;
    MyCalendarThree() {

    }

    int book(int startTime, int endTime) {
        events[startTime]++;
        events[endTime]--;
        int maxBooking = 0, currentBooking = 0;
        for (auto& event : events) {
            currentBooking += event.second;
            maxBooking = max(maxBooking, currentBooking);
        }
        events.clear();
        for (int i = startTime; i < endTime; i++) {
            if (events.find(i) != events.end()) {
                events[i]++;
            } else {
                events[i] = 1;
            }
        }
        return maxBooking;
    }
};

